"use client";

import { useState, useMemo, memo } from "react";
import { ChevronDown } from "lucide-react";
import type { AgentConfig } from "@polpo-ai/sdk";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface ChatAgentSelectorProps {
  /** Agents list (from useAgents().agents) */
  agents: AgentConfig[] | undefined;
  /** Currently selected agent name */
  selected: string | undefined;
  /** Called when an agent is selected */
  onSelect: (agentName: string) => void;
  /** Label shown when no agent is selected */
  fallbackLabel?: string;
  /** Custom avatar renderer */
  renderAvatar?: (agent: AgentConfig, size: number) => React.ReactNode;
  /** Additional className */
  className?: string;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const ChatAgentSelector = memo(function ChatAgentSelector({
  agents,
  selected,
  onSelect,
  fallbackLabel = "Select agent",
  renderAvatar,
  className,
}: ChatAgentSelectorProps) {
  const [open, setOpen] = useState(false);

  const items = useMemo(
    () =>
      agents?.map((a) => ({
        agent: a,
        displayName: a.identity?.displayName || a.name,
        letter: (a.identity?.displayName || a.name).charAt(0).toUpperCase(),
      })) ?? [],
    [agents],
  );

  const selectedItem = selected
    ? items.find((i) => i.agent.name === selected)
    : items[0] || null;

  return (
    <div className={`relative ${className || ""}`}>
      <button
        type="button"
        className="flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium text-gray-600 hover:bg-gray-100 transition-colors"
        onClick={() => setOpen(!open)}
      >
        {selectedItem ? (
          <>
            {renderAvatar ? (
              renderAvatar(selectedItem.agent, 20)
            ) : (
              <span className="flex items-center justify-center size-5 rounded bg-gray-200 text-[10px] font-semibold text-gray-600">
                {selectedItem.letter}
              </span>
            )}
            {selectedItem.displayName}
          </>
        ) : (
          fallbackLabel
        )}
        <ChevronDown className="size-3" />
      </button>

      {open && (
        <>
          {/* Backdrop */}
          <div
            className="fixed inset-0 z-40"
            onClick={() => setOpen(false)}
          />
          {/* Dropdown */}
          <div className="absolute bottom-full left-0 mb-1 bg-gray-50 border border-gray-200 rounded-xl shadow-lg py-1 min-w-[180px] z-50">
            {items.map((item) => (
              <button
                key={item.agent.name}
                type="button"
                className={`flex items-center gap-2 w-full px-3 py-2 text-xs text-left hover:bg-gray-50 transition-colors ${
                  selected === item.agent.name ? "bg-gray-50 font-semibold" : ""
                }`}
                onClick={() => {
                  onSelect(item.agent.name);
                  setOpen(false);
                }}
              >
                {renderAvatar ? (
                  renderAvatar(item.agent, 20)
                ) : (
                  <span className="flex items-center justify-center size-5 rounded bg-gray-200 text-[10px] font-semibold text-gray-600">
                    {item.letter}
                  </span>
                )}
                {item.displayName}
              </button>
            ))}
          </div>
        </>
      )}
    </div>
  );
});

"use client";

import { useState, useEffect, useRef, useCallback, type ReactNode } from "react";
import {
  Check,
  ChevronLeft,
  ChevronRight,
  ListChecks,
  MessageSquareMore,
  PenLine,
  Send,
  SkipForward,
  AlertTriangle,
} from "lucide-react";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

interface AskUserQuestion {
  id: string;
  question: string;
  header?: string;
  options?: { label: string; description?: string }[];
  multiple?: boolean;
  custom?: boolean;
}

type StepStatus = "answered" | "empty";

export interface ChatAskUserProps {
  /** The pending tool call arguments — expects { questions: AskUserQuestion[] } */
  questions: AskUserQuestion[];
  /** Called when the user submits answers */
  onSubmit: (answers: { questionId: string; selected: string[] }[]) => void;
  /** Whether the panel is disabled (e.g. already submitted) */
  disabled?: boolean;
}

/* ------------------------------------------------------------------ */
/*  Button helpers (self-contained, no external UI dep)                */
/* ------------------------------------------------------------------ */

function Btn({
  children,
  variant = "default",
  disabled,
  onClick,
  className = "",
}: {
  children: ReactNode;
  variant?: "default" | "ghost" | "outline" | "accent";
  disabled?: boolean;
  onClick?: () => void;
  className?: string;
}) {
  const base = "inline-flex items-center justify-center font-medium rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed";
  const sizes = "px-3 py-1.5 text-xs";
  const variants = {
    default: "bg-gray-900 text-white hover:bg-gray-700",
    ghost: "bg-transparent hover:bg-gray-100 text-gray-500",
    outline: "border border-gray-200 bg-transparent hover:bg-gray-50 text-gray-700",
    accent: "bg-blue-600 text-white hover:bg-blue-500",
  };
  return (
    <button
      type="button"
      disabled={disabled}
      onClick={onClick}
      className={`${base} ${sizes} ${variants[variant]} ${className}`}
    >
      {children}
    </button>
  );
}

/* ------------------------------------------------------------------ */
/*  Question Card                                                      */
/* ------------------------------------------------------------------ */

function QuestionCard({
  q,
  sel,
  customText,
  disabled,
  submitting,
  onToggle,
  onCustomChange,
  onEnterSubmit,
}: {
  q: AskUserQuestion;
  sel: Set<string>;
  customText: string;
  disabled?: boolean;
  submitting: boolean;
  onToggle: (label: string, multiple: boolean) => void;
  onCustomChange: (text: string) => void;
  onEnterSubmit: () => void;
}) {
  const isMultiple = q.multiple ?? false;
  const showCustom = q.custom !== false;

  return (
    <div className="rounded-xl border border-blue-200/50 bg-blue-50/30 p-4">
      <div className="flex items-start gap-2 mb-3">
        <MessageSquareMore className="size-4 text-blue-600 mt-0.5 shrink-0" />
        <div className="flex-1 min-w-0">
          {q.header && (
            <p className="text-[10px] font-semibold text-blue-600/80 uppercase tracking-wider mb-0.5">{q.header}</p>
          )}
          <p className="font-medium text-gray-900">{q.question}</p>
        </div>
        {isMultiple && (
          <span className="text-[9px] font-medium text-gray-500 border border-gray-200 rounded px-1.5 py-0.5 shrink-0">
            Multi-select
          </span>
        )}
      </div>

      {q.options && q.options.length > 0 && (
        <div className="flex flex-wrap gap-1.5 mb-3">
          {q.options.map((opt) => {
            const isSelected = sel.has(opt.label);
            return (
              <button
                key={opt.label}
                type="button"
                disabled={disabled || submitting}
                className={`inline-flex items-center gap-1.5 rounded-lg border px-3 py-1.5 text-sm transition-all disabled:opacity-50 disabled:cursor-not-allowed ${
                  isSelected
                    ? "border-blue-400 bg-blue-50 text-blue-700 font-medium shadow-sm"
                    : "border-gray-200 bg-gray-50/60 text-gray-600 hover:border-blue-300 hover:bg-blue-50/30 hover:text-gray-900"
                }`}
                onClick={() => onToggle(opt.label, isMultiple)}
              >
                <span
                  className={`flex size-4 shrink-0 items-center justify-center rounded-full border transition-colors ${
                    isSelected ? "border-blue-500 bg-blue-500" : "border-gray-300"
                  }`}
                >
                  {isSelected && <Check className="size-2.5 text-white" />}
                </span>
                <span>{opt.label}</span>
              </button>
            );
          })}
        </div>
      )}

      {q.options?.some((o) => o.description) && sel.size > 0 && (
        <div className="mb-3 pl-1">
          {q.options
            ?.filter((o) => sel.has(o.label) && o.description)
            .map((o) => (
              <p key={o.label} className="text-xs text-gray-500 leading-snug">
                <span className="font-medium text-gray-700">{o.label}:</span> {o.description}
              </p>
            ))}
        </div>
      )}

      {showCustom && (
        <div className="flex items-center gap-2">
          <PenLine className="size-3.5 text-gray-400 shrink-0" />
          <input
            type="text"
            placeholder="Type your own answer..."
            className="flex-1 h-8 px-3 text-sm rounded-lg border border-gray-200 bg-transparent text-gray-900 placeholder:text-gray-400 outline-none focus:border-blue-400 transition-colors"
            value={customText}
            disabled={disabled || submitting}
            onChange={(e) => onCustomChange(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                onEnterSubmit();
              }
            }}
          />
        </div>
      )}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Warning banner                                                     */
/* ------------------------------------------------------------------ */

function WarningBanner({ children }: { children: ReactNode }) {
  return (
    <div className="flex items-center gap-2 px-3 py-2 rounded-md bg-amber-50 border border-amber-200 text-xs text-amber-700">
      <AlertTriangle className="size-3.5 shrink-0" />
      <span>{children}</span>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Main Component                                                     */
/* ------------------------------------------------------------------ */

export function ChatAskUser({ questions, onSubmit, disabled }: ChatAskUserProps) {
  const [selections, setSelections] = useState<Record<string, Set<string>>>(() => {
    const init: Record<string, Set<string>> = {};
    for (const q of questions) init[q.id] = new Set();
    return init;
  });
  const [customTexts, setCustomTexts] = useState<Record<string, string>>(() => {
    const init: Record<string, string> = {};
    for (const q of questions) init[q.id] = "";
    return init;
  });
  const [submitting, setSubmitting] = useState(false);
  const [step, setStep] = useState(0);
  const [partialWarning, setPartialWarning] = useState(false);
  const [skipWarning, setSkipWarning] = useState(false);

  const isWizard = questions.length > 1;
  const isSummaryStep = isWizard && step === questions.length;
  const current = !isSummaryStep ? questions[step] : undefined;

  const toggleOption = useCallback((questionId: string, label: string, multiple: boolean) => {
    setSelections((prev) => {
      const curr = new Set(prev[questionId]);
      if (curr.has(label)) curr.delete(label);
      else {
        if (!multiple) curr.clear();
        curr.add(label);
      }
      return { ...prev, [questionId]: curr };
    });
  }, []);

  const getStatus = useCallback(
    (q: AskUserQuestion): StepStatus => {
      const sel = selections[q.id];
      const txt = customTexts[q.id]?.trim();
      return (sel && sel.size > 0) || (txt && txt.length > 0) ? "answered" : "empty";
    },
    [selections, customTexts],
  );

  const statuses = questions.map(getStatus);
  const answeredCount = statuses.filter((s) => s === "answered").length;
  const emptyCount = statuses.filter((s) => s === "empty").length;
  const allAnswered = emptyCount === 0;
  const hasAnyAnswer = answeredCount > 0;

  // Auto-navigate to summary when all answered
  const prevAllAnswered = useRef(false);
  useEffect(() => {
    if (isWizard && allAnswered && !prevAllAnswered.current && !isSummaryStep) setStep(questions.length);
    prevAllAnswered.current = allAnswered;
  }, [allAnswered, isWizard, isSummaryStep, questions.length]);

  useEffect(() => {
    if (!isSummaryStep) setPartialWarning(false);
  }, [isSummaryStep]);
  useEffect(() => {
    setSkipWarning(false);
  }, [step]);

  const buildAnswers = useCallback(() => {
    return questions.map((q) => {
      const selected = Array.from(selections[q.id] ?? []);
      const custom = customTexts[q.id]?.trim();
      if (custom && !selected.includes(custom)) selected.push(custom);
      return { questionId: q.id, selected };
    });
  }, [questions, selections, customTexts]);

  const handleSubmit = useCallback(() => {
    if (submitting || disabled) return;
    if (emptyCount > 0 && !partialWarning) {
      setPartialWarning(true);
      return;
    }
    if (!hasAnyAnswer) return;
    setSubmitting(true);
    setPartialWarning(false);
    onSubmit(buildAnswers());
  }, [submitting, disabled, emptyCount, partialWarning, hasAnyAnswer, buildAnswers, onSubmit]);

  const handleSkip = useCallback(() => {
    if (submitting || disabled) return;
    if (!skipWarning) {
      setSkipWarning(true);
      return;
    }
    setSubmitting(true);
    setSkipWarning(false);
    const answers = questions.map((q) => ({ questionId: q.id, selected: [] as string[] }));
    onSubmit(answers);
  }, [submitting, disabled, skipWarning, questions, onSubmit]);

  const advanceStep = useCallback(() => {
    const nextEmpty = questions.findIndex((q, i) => i > step && getStatus(q) === "empty");
    setStep(nextEmpty >= 0 ? nextEmpty : questions.length);
  }, [questions, step, getStatus]);

  // ── Single question — flat layout ──
  if (!isWizard) {
    return (
      <div className="space-y-3">
        <QuestionCard
          q={questions[0]}
          sel={selections[questions[0].id] ?? new Set()}
          customText={customTexts[questions[0].id] ?? ""}
          disabled={disabled}
          submitting={submitting}
          onToggle={(label, multiple) => toggleOption(questions[0].id, label, multiple)}
          onCustomChange={(text) => setCustomTexts((prev) => ({ ...prev, [questions[0].id]: text }))}
          onEnterSubmit={() => {
            if (hasAnyAnswer) handleSubmit();
          }}
        />
        <div className="flex justify-end">
          <Btn variant="accent" disabled={!hasAnyAnswer || submitting} onClick={handleSubmit} className="gap-1.5">
            {submitting ? (
              <>
                <span className="size-3.5 animate-spin rounded-full border-2 border-current border-t-transparent" />
                Sending...
              </>
            ) : (
              <>
                <Send className="size-3.5" />
                Send answer
              </>
            )}
          </Btn>
        </div>
      </div>
    );
  }

  // ── Wizard layout ──
  return (
    <div>
      {/* Horizontal tabs */}
      <div className="flex items-center gap-1 mb-3 overflow-x-auto pb-1">
        {questions.map((q, idx) => {
          const status = statuses[idx];
          const isActive = idx === step;
          return (
            <button
              key={q.id}
              type="button"
              onClick={() => setStep(idx)}
              className={`flex items-center gap-1.5 px-2.5 py-1.5 rounded-md text-xs font-medium transition-all whitespace-nowrap shrink-0 ${
                isActive
                  ? "bg-blue-50 text-blue-700 border border-blue-200"
                  : "text-gray-500 hover:bg-gray-50 border border-transparent"
              }`}
            >
              <span
                className={`size-2 rounded-full shrink-0 ${
                  status === "answered" ? "bg-green-500" : isActive ? "bg-blue-500" : "bg-gray-200"
                }`}
              />
              {q.header || `Q${idx + 1}`}
            </button>
          );
        })}
        <button
          type="button"
          onClick={() => setStep(questions.length)}
          className={`flex items-center gap-1.5 px-2.5 py-1.5 rounded-md text-xs font-medium transition-all whitespace-nowrap shrink-0 ${
            isSummaryStep
              ? "bg-blue-50 text-blue-700 border border-blue-200"
              : "text-gray-500 hover:bg-gray-50 border border-transparent"
          }`}
        >
          <ListChecks className="size-3" />
          Summary
        </button>
      </div>

      {/* Summary step */}
      {isSummaryStep ? (
        <div className="space-y-3">
          <div className="rounded-xl border border-blue-200/50 bg-blue-50/30 p-4 space-y-3">
            <div className="flex items-center gap-2 mb-1">
              <ListChecks className="size-4 text-blue-600" />
              <p className="text-sm font-semibold text-gray-900">Summary</p>
              <span className="text-[9px] font-medium text-gray-500 border border-gray-200 rounded px-1.5 py-0.5 ml-auto">
                {answeredCount}/{questions.length} answered
              </span>
            </div>
            <div className="space-y-2">
              {questions.map((q, idx) => {
                const status = statuses[idx];
                const sel = selections[q.id];
                const txt = customTexts[q.id]?.trim();
                const answer =
                  status === "answered"
                    ? [...(sel?.size ? Array.from(sel) : []), ...(txt ? [txt] : [])].join(", ")
                    : undefined;
                return (
                  <button
                    key={q.id}
                    type="button"
                    onClick={() => setStep(idx)}
                    className="flex items-start gap-2 w-full text-left rounded-lg px-3 py-2 hover:bg-gray-50 transition-colors"
                  >
                    <span
                      className={`size-2 rounded-full shrink-0 mt-1.5 ${
                        status === "answered" ? "bg-green-500" : "bg-gray-200"
                      }`}
                    />
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-medium text-gray-900">{q.question}</p>
                      {answer ? (
                        <p className="text-xs text-gray-500 truncate">{answer}</p>
                      ) : (
                        <p className="text-xs text-gray-400 italic">Not answered yet</p>
                      )}
                    </div>
                    <ChevronRight className="size-3 text-gray-400 mt-1 shrink-0" />
                  </button>
                );
              })}
            </div>
          </div>

          {partialWarning && (
            <WarningBanner>
              {emptyCount} question{emptyCount > 1 ? "s" : ""} not answered. Press send again to confirm.
            </WarningBanner>
          )}
          {skipWarning && (
            <WarningBanner>Skip all questions without answering? Press skip again to confirm.</WarningBanner>
          )}

          <div className="flex items-center justify-between pt-1">
            <Btn variant="ghost" onClick={() => setStep(questions.length - 1)} className="gap-1">
              <ChevronLeft className="size-3.5" />
              Back
            </Btn>
            <div className="flex items-center gap-2">
              {!allAnswered && (
                <Btn variant="ghost" disabled={submitting} onClick={handleSkip} className="gap-1">
                  <SkipForward className="size-3.5" />
                  {skipWarning ? "Confirm skip" : "Skip all"}
                </Btn>
              )}
              <Btn variant="accent" disabled={!hasAnyAnswer || submitting} onClick={handleSubmit} className="gap-1.5">
                {submitting ? (
                  <>
                    <span className="size-3.5 animate-spin rounded-full border-2 border-current border-t-transparent" />
                    Sending...
                  </>
                ) : (
                  <>
                    <Send className="size-3.5" />
                    Send answers
                  </>
                )}
              </Btn>
            </div>
          </div>
        </div>
      ) : current ? (
        <>
          <QuestionCard
            q={current}
            sel={selections[current.id] ?? new Set()}
            customText={customTexts[current.id] ?? ""}
            disabled={disabled}
            submitting={submitting}
            onToggle={(label, multiple) => toggleOption(current.id, label, multiple)}
            onCustomChange={(text) => setCustomTexts((prev) => ({ ...prev, [current.id]: text }))}
            onEnterSubmit={advanceStep}
          />

          {skipWarning && (
            <div className="mt-3">
              <WarningBanner>Skip all questions without answering? Press skip again to confirm.</WarningBanner>
            </div>
          )}

          <div className="flex items-center justify-between mt-3">
            <Btn variant="ghost" disabled={step === 0} onClick={() => setStep(step - 1)} className="gap-1">
              <ChevronLeft className="size-3.5" />
              Back
            </Btn>
            <div className="flex items-center gap-2">
              <Btn variant="ghost" disabled={submitting} onClick={handleSkip} className="gap-1">
                <SkipForward className="size-3.5" />
                {skipWarning ? "Confirm skip" : "Skip all"}
              </Btn>
              <Btn
                variant={getStatus(current) === "answered" ? "default" : "outline"}
                onClick={() => {
                  setSkipWarning(false);
                  advanceStep();
                }}
                className="gap-1"
              >
                Next
                <ChevronRight className="size-3.5" />
              </Btn>
            </div>
          </div>
        </>
      ) : null}
    </div>
  );
}

"use client";

import {
  useState,
  useRef,
  useCallback,
  useEffect,
  type KeyboardEvent,
  type ChangeEvent,
  type DragEvent,
  type ReactNode,
} from "react";
import { ArrowUp, Square, Plus, X, Upload } from "lucide-react";
import { useChatContext } from "./chat-provider";
import { useSubmitHandler } from "../hooks/use-submit-handler";
import { useDocumentDrag } from "../hooks/use-document-drag";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

interface PendingFile {
  id: string;
  file: File;
  url: string;
}

export interface ChatInputProps {
  /** Placeholder text for the textarea */
  placeholder?: string;
  /** Hint text below the input */
  hint?: string;
  /** Whether file attachments are enabled (default: true) */
  allowAttachments?: boolean;
  /** Additional className on the outer wrapper */
  className?: string;
  /** Custom submit button renderer */
  renderSubmit?: (props: { isStreaming: boolean; onStop: () => void }) => ReactNode;
}


/* ------------------------------------------------------------------ */
/*  Shared input logic                                                 */
/* ------------------------------------------------------------------ */

function useChatInputState() {
  const { sendMessage, isStreaming, abort, uploadFile } = useChatContext();
  const handleSubmit = useSubmitHandler(sendMessage, uploadFile);
  const dragging = useDocumentDrag();

  const [text, setText] = useState("");
  const [files, setFiles] = useState<PendingFile[]>([]);
  const [isSending, setIsSending] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const filesRef = useRef(files);
  filesRef.current = files;
  const textRef = useRef(text);
  textRef.current = text;

  // Auto-resize textarea
  useEffect(() => {
    const el = textareaRef.current;
    if (!el) return;
    el.style.height = "auto";
    el.style.height = `${Math.min(el.scrollHeight, 200)}px`;
  }, [text]);

  // Add files helper
  const addFiles = useCallback((incoming: FileList | File[]) => {
    const arr = Array.from(incoming);
    setFiles((prev) => {
      const existing = new Set(prev.map((f) => f.file.name));
      const fresh = arr.filter((f) => !existing.has(f.name));
      return [
        ...prev,
        ...fresh.map((file) => ({
          id: Math.random().toString(36).slice(2),
          file,
          url: URL.createObjectURL(file),
        })),
      ];
    });
  }, []);

  const removeFile = useCallback((id: string) => {
    setFiles((prev) => {
      const f = prev.find((p) => p.id === id);
      if (f) URL.revokeObjectURL(f.url);
      return prev.filter((p) => p.id !== id);
    });
  }, []);

  // Cleanup blob URLs on unmount via ref (avoids stale closure)
  useEffect(
    () => () => {
      filesRef.current.forEach((f) => URL.revokeObjectURL(f.url));
    },
    [],
  );

  // Submit — reads from refs for stable callback
  const submit = useCallback(async () => {
    if (isSending) return;
    const trimmed = textRef.current.trim();
    const currentFiles = filesRef.current;
    if (!trimmed && currentFiles.length === 0) return;

    setIsSending(true);
    try {
      await handleSubmit({
        text: trimmed,
        files: currentFiles.map((f) => ({ url: f.url, filename: f.file.name })),
      });
      setText("");
      setFiles([]);
    } finally {
      setIsSending(false);
    }

    setTimeout(() => textareaRef.current?.focus(), 0);
  }, [handleSubmit, isSending]);

  // Keyboard: Enter to send, Shift+Enter for newline
  const onKeyDown = useCallback(
    (e: KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === "Enter" && !e.shiftKey) {
        e.preventDefault();
        submit();
      }
    },
    [submit],
  );

  // File input change
  const onFileChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      if (e.target.files) addFiles(e.target.files);
      e.target.value = "";
    },
    [addFiles],
  );

  // Drop handler
  const onDrop = useCallback(
    (e: DragEvent<HTMLDivElement>) => {
      e.preventDefault();
      if (e.dataTransfer.files.length > 0) {
        addFiles(e.dataTransfer.files);
      }
    },
    [addFiles],
  );

  return { text, setText, files, isSending, isStreaming, abort, dragging, textareaRef, fileInputRef, submit, onKeyDown, onFileChange, onDrop, removeFile, addFiles };
}

/* ------------------------------------------------------------------ */
/*  Pending files display                                              */
