const SessionItem = memo(function SessionItem({
  session,
  agentMap,
  isActive,
  onSelect,
  onDelete,
  renderAvatar,
}: {
  session: ChatSession;
  agentMap: Map<string, AgentConfig>;
  isActive: boolean;
  onSelect: (id: string) => void;
