  const handleDelete = useCallback(
    (e: React.MouseEvent) => {
      e.stopPropagation();
      onDelete?.(session.id);
    },
    [onDelete, session.id],
  );

  return (
    <div
      role="button"
      tabIndex={0}
      onClick={() => onSelect(session.id)}
