/* ------------------------------------------------------------------ */
/*  Main component                                                     */
/* ------------------------------------------------------------------ */

export function ChatSessionsByAgent({
  sessions,
  agents,
  onSelect,
  isLoading,
  emptyMessage = "No conversations yet",
  className,
  renderAvatar,
}: ChatSessionsByAgentProps) {
  const agentMap = useMemo(() => {
    const map = new Map<string, AgentConfig>();
    if (agents) for (const a of agents) map.set(a.name, a);
    return map;
  }, [agents]);

  const groups = useMemo<AgentSessionGroup[]>(() => {
    const map = new Map<string, ChatSession[]>();
    for (const s of sessions) {
      const name = s.agent || "assistant";
      if (!map.has(name)) map.set(name, []);
      map.get(name)!.push(s);
    }
    return Array.from(map.entries())
      .sort((a, b) => {
        const aLatest = a[1][0]?.updatedAt || "";
        const bLatest = b[1][0]?.updatedAt || "";
        return bLatest.localeCompare(aLatest);
      })
      .map(([agentName, agentSessions]) => {
        const agent = agentMap.get(agentName);
        return {
          agentName,
          agent,
          displayName: agent?.identity?.displayName || agent?.name || agentName,
          sessions: agentSessions,
        };
      });
  }, [sessions, agentMap]);

  if (isLoading) {
    return (
      <div className={`flex flex-col gap-1 ${className || ""}`}>
        {Array.from({ length: 4 }).map((_, i) => (
          <div key={i} className="flex items-center gap-3.5 px-4 py-3.5">
            <div className="size-9 rounded-lg bg-gray-100 animate-pulse" />
            <div className="flex-1 space-y-1.5">
              <div className="h-3.5 w-1/2 rounded bg-gray-100 animate-pulse" />
              <div className="h-3 w-1/3 rounded bg-gray-100 animate-pulse" />
            </div>
            <div className="h-5 w-8 rounded-full bg-gray-100 animate-pulse" />
          </div>
        ))}
      </div>
    );
  }

  if (groups.length === 0) {
    return (
      <div className={`flex flex-col items-center justify-center py-12 ${className || ""}`}>
        <Users className="size-8 text-gray-300 mb-3" />
        <p className="text-sm text-gray-400">{emptyMessage}</p>
      </div>
    );
  }

  return (
    <div className={`flex flex-col gap-0.5 ${className || ""}`}>
      {groups.map((g) => (
        <AgentGroupItem
          key={g.agentName}
          group={g}
          onSelect={onSelect}
          renderAvatar={renderAvatar}
        />
      ))}
    </div>
  );
}

/**
 * Skeleton loaders for chat UI — mirrors the exact layout of ChatMessageItem
 * so the loading state feels native, not jarring.
 */

function Bone({ width, height = 14 }: { width: string; height?: number }) {
  return (
    <div
      className="bg-gray-200 animate-pulse"
      style={{ width, height, borderRadius: height > 20 ? 12 : 6 }}
    />
  );
}

/** Skeleton for an AI message: avatar + name + text lines */
export function MessageSkeleton({ lines = 3 }: { lines?: number }) {
  const widths = ["85%", "70%", "55%", "90%", "40%"];
  return (
    <div className="w-full px-6 pt-4 pb-6">
      <div className="max-w-3xl mx-auto">
        <div className="flex items-center gap-2 mb-2">
          <div className="size-6 rounded-md bg-gray-200 animate-pulse shrink-0" />
          <Bone width="80px" height={13} />
        </div>
        <div className="flex flex-col gap-2">
          {Array.from({ length: lines }, (_, i) => (
            <Bone key={i} width={widths[i % widths.length]} />
          ))}
        </div>
      </div>
    </div>
  );
}

/** Skeleton for a user message: right-aligned bubble */
export function UserMessageSkeleton() {
  return (
    <div className="w-full px-6 py-3">
      <div className="max-w-3xl mx-auto flex justify-end">
        <div className="w-[45%] min-w-[120px] h-[42px] rounded-[18px_18px_4px_18px] bg-gray-200 animate-pulse" />
      </div>
    </div>
  );
}

/** Full conversation skeleton — alternating user/AI messages */
export function ChatSkeleton({ count = 3 }: { count?: number }) {
  return (
    <div className="py-2">
      {Array.from({ length: count }, (_, i) => (
        <div key={i}>
          <UserMessageSkeleton />
          <MessageSkeleton lines={i === 0 ? 2 : i === 1 ? 4 : 3} />
        </div>
      ))}
    </div>
  );
}

"use client";

import type { ReactNode } from "react";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface ChatSuggestion {
  /** Icon component rendered before the text */
  icon?: ReactNode;
  /** Suggestion text — also used as the message sent on click */
  text: string;
}

export interface ChatSuggestionsProps {
  /** List of suggestions to display */
  suggestions: ChatSuggestion[];
  /** Called when a suggestion is clicked */
  onSelect: (text: string) => void;
  /** Grid columns (default: 2) */
  columns?: 1 | 2 | 3;
  /** Additional className */
  className?: string;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

const gridCols = {
  1: "grid-cols-1",
  2: "grid-cols-2",
  3: "grid-cols-3",
} as const;

export function ChatSuggestions({
  suggestions,
  onSelect,
  columns = 2,
  className,
}: ChatSuggestionsProps) {
  if (suggestions.length === 0) return null;

  return (
    <div className={`grid ${gridCols[columns]} gap-2 ${className || ""}`}>
      {suggestions.map((s) => (
        <button
          key={s.text}
          type="button"
          className="flex items-center gap-2 px-4 py-3 rounded-xl border border-gray-200 bg-transparent text-xs text-gray-600 text-left hover:bg-gray-50 hover:border-gray-300 transition-colors"
          onClick={() => onSelect(s.text)}
        >
          {s.icon && (
            <span className="shrink-0 text-gray-400">{s.icon}</span>
          )}
          {s.text}
        </button>
      ))}
    </div>
  );
}

"use client";

import { useCallback, type ReactNode } from "react";
import { ChatProvider } from "./chat-provider";
import { useChatContext } from "./chat-provider";
import { ChatMessages, type ChatMessagesHandle } from "./chat-messages";
import { ChatMessage, type ChatMessageProps } from "./chat-message";
import { ChatInput } from "./chat-input";
import { streamdownComponents as defaultStreamdownComponents } from "./streamdown-code";

// ── Props ──

export interface ChatRenderContext {
  hasMessages: boolean;
}

export interface ChatProps {
  /** Session ID — omit for new chats */
  sessionId?: string;
  /** Agent name for completions */
  agent?: string;
  /** Called when a new session is created */
  onSessionCreated?: (sessionId: string) => void;
  /** Called on each stream update (useful for external scroll control) */
  onUpdate?: () => void;
  /** Custom message renderer — if omitted, uses ChatMessage with defaults */
  renderMessage?: (msg: ChatMessageProps["msg"], index: number, isLast: boolean, isStreaming: boolean) => ReactNode;
  /** Avatar ReactNode shown on assistant messages */
  avatar?: ReactNode;
  /** Agent display name shown on assistant messages */
  agentName?: string;
  /** Streamdown components override for code blocks etc. */
  streamdownComponents?: Record<string, unknown>;
  /** Number of skeleton items while loading */
  skeletonCount?: number;
  /** Placeholder text for the default input */
  inputPlaceholder?: string;
  /** Hint text below the default input */
  inputHint?: string;
  /** Whether file attachments are enabled on the default input (default: true) */
  allowAttachments?: boolean;
  /** Children rendered after the message list — replaces the default ChatInput.
   *  Can be a render function receiving `{ hasMessages }` for conditional rendering. */
  children?: ReactNode | ((ctx: ChatRenderContext) => ReactNode);
  /** Additional className on the outer container */
  className?: string;
}

// ── Inner component (needs context) ──

function ChatInner({
  ref,
  renderMessage,
  avatar,
  agentName,
  streamdownComponents,
  skeletonCount,
  inputPlaceholder,
  inputHint,
  allowAttachments,
  children,
  className,
}: Omit<ChatProps, "sessionId" | "agent" | "onSessionCreated" | "onUpdate"> & {
  ref?: React.Ref<ChatMessagesHandle>;
}) {
  const { messages } = useChatContext();
  const hasMessages = messages.length > 0;
  const hasChildren = children !== undefined && children !== null;
  const isRenderFunction = typeof children === "function";

  const defaultRender = useCallback(
    (msg: ChatMessageProps["msg"], _index: number, isLast: boolean, isStreaming: boolean) => (
      <ChatMessage
        msg={msg}
        isLast={isLast}
        isStreaming={isStreaming}
        avatar={avatar}
        agentName={agentName}
        streamdownComponents={(streamdownComponents ?? defaultStreamdownComponents) as Record<string, unknown>}
      />
    ),
    [avatar, agentName, streamdownComponents],
  );

  // Resolve children content
  let content: ReactNode;
  if (isRenderFunction) {
    content = children({ hasMessages });
  } else if (hasChildren) {
    content = children;
  } else {
    content = (
      <ChatInput
        placeholder={inputPlaceholder}
        hint={inputHint}
        allowAttachments={allowAttachments}
      />
    );
  }

  // When using render function and no messages yet, skip the message list
  // (landing page pattern)
  if (isRenderFunction && !hasMessages) {
    return (
      <div className={`flex flex-col min-w-0 min-h-0 ${className || ""}`}>
        {content}
      </div>
    );
  }

  return (
    <div className={`flex flex-col min-w-0 min-h-0 ${className || ""}`}>
      <ChatMessages
        ref={ref}
        renderItem={renderMessage || defaultRender}
        skeletonCount={skeletonCount}
        className="flex-1"
      />
      {content}
    </div>
  );
}

// ── Public component ──

export function Chat({
  sessionId,
  agent,
  onSessionCreated,
  onUpdate,
  ref,
  ...rest
}: ChatProps & { ref?: React.Ref<ChatMessagesHandle> }) {
  return (
    <ChatProvider
      sessionId={sessionId}
      agent={agent}
      onSessionCreated={onSessionCreated}
      onUpdate={onUpdate}
    >
      <ChatInner ref={ref} {...rest} />
    </ChatProvider>
  );
}
